<div style="display:flex;justify-content:space-between;font-size:9px;color:#666;margin-bottom:8px"><div>تاريخ الإيصال: <b>${p.issue_date||"—"}</b></div><div style="direction:ltr">Receipt No: <b>${p.invoice_number||"—"}</b></div></div>
